
/* 类名要对应回 name 的属性值 */
.plusBack-enter-active {
  animation: move 1s;
}
.plusBack-leave-active {
  animation: move 1s reverse;
}
@keyframes move {
  from {
      transform: translateX(-100%);
  }
  to {
      transform: translate(0);
  }
}
.page-component-up{
  position: fixed;
  cursor: pointer;
  text-align: center;
  transition: .3s;
  box-shadow: 0 0 6px rgba(0,0,0,.12);
  z-index: 99;
  i{
    color: #409eff;
    display: block;
    line-height: inherit;
    text-align: center;
    font-size: 18px;
  }
}
